// BuildFeedbackEmail constructs a complete RFC 5322-compliant email message
// with HTML body containing user feedback information.
// The returned emailBody includes headers and body, ready to be sent via smtp.SendMail.
func BuildFeedbackEmail(fromAddr string, toAddr string, userName string, subject string, feedbackContent string) (emailBody string, err error) {
	// Basic validation
	if fromAddr == "" || toAddr == "" {
		return "", fmt.Errorf("fromAddr and toAddr must not be empty")
	}

	// Validate email addresses format (optional but good practice)
	if _, err := mail.ParseAddress(fromAddr); err != nil {
		return "", fmt.Errorf("invalid fromAddr: %w", err)
	}
	if _, err := mail.ParseAddress(toAddr); err != nil {
		return "", fmt.Errorf("invalid toAddr: %w", err)
	}

	// Prevent header injection by checking for newlines in user-controlled fields
	if hasNewline(subject) || hasNewline(userName) {
		return "", fmt.Errorf("subject and userName must not contain newlines")
	}

	// HTML escape user content to prevent XSS attacks and ensure valid HTML
	escapedUserName := html.EscapeString(userName)
	escapedSubject := html.EscapeString(subject)
	escapedFeedback := html.EscapeString(feedbackContent)

	// Construct email subject
	emailSubject := fmt.Sprintf("Feedback: %s", subject)

	// Format date according to RFC 5322 (required for RFC compliance)
	dateStr := time.Now().Format(time.RFC1123Z)

	// Construct email headers
	headers := fmt.Sprintf("From: %s\r\nTo: %s\r\nSubject: %s\r\nDate: %s\r\nMIME-Version: 1.0\r\nContent-Type: text/html; charset=UTF-8\r\n\r\n",
		fromAddr,
		toAddr,
		emailSubject,
		dateStr,
	)

	// Construct HTML body with escaped content
	htmlBody := fmt.Sprintf(`<!DOCTYPE html>
<html>
<head>
  <meta charset="UTF-8">
  <title>User Feedback</title>
</head>
<body>
  <h2>User Feedback Received</h2>
  <p><strong>Submitted by:</strong> %s</p>
  <p><strong>Subject:</strong> %s</p>
  <div><strong>Message:</strong><br>
    <pre style="font-family: Arial, sans-serif; background-color: #f9f9f9; padding: 10px; border: 1px solid #ddd;">%s</pre>
  </div>
</body>
</html>`,
		escapedUserName,
		escapedSubject,
		escapedFeedback,
	)

	// Combine headers and body
	emailMessage := headers + htmlBody

	return emailMessage, nil
}

// hasNewline checks if a string contains CR or LF characters to prevent header injection attacks
func hasNewline(s string) bool {
	for i := 0; i < len(s); i++ {
		if s[i] == '\n' || s[i] == '\r' {
			return true
		}
	}
	return false
}

