                <div class="value">{{.UserName}}</div>
            </div>
            <div class="field">
                <div class="label">Subject</div>
                <div class="value">{{.Subject}}</div>
            </div>
            <div class="field">
                <div class="label">Feedback Content</div>
                <div class="feedback-box">{{.FeedbackContent}}</div>
            </div>
        </div>
        <div class="footer">
            This email was generated automatically by the feedback system.
        </div>
    </div>
</body>
</html>`

	type TemplateData struct {
		UserName        string
