		FeedbackContent string
	}

	data := TemplateData{
		UserName:        userName,
		Subject:         subject,
		FeedbackContent: feedbackContent,
	}

	// Parse and execute HTML template with automatic HTML escaping
	tmpl, err := template.New("feedbackEmail").Parse(emailTemplate)
	if err != nil {
		return "", fmt.Errorf("template parsing error: %w", err)
	}

	var htmlBody bytes.Buffer
	if err := tmpl.Execute(&htmlBody, data); err != nil {
