	if _, err := mail.ParseAddress(fromAddr); err != nil {
		return "", fmt.Errorf("invalid fromAddr: %w", err)
	}
	if _, err := mail.ParseAddress(toAddr); err != nil {
		return "", fmt.Errorf("invalid toAddr: %w", err)
	}

	// Sanitize subject to prevent header injection (remove CR and LF characters)
	safeSubject := strings.ReplaceAll(strings.ReplaceAll(subject, "\r", ""), "\n", "")

	// Construct email subject with prefix
	emailSubject := fmt.Sprintf("Feedback: %s", safeSubject)

	// Encode subject if it contains non-ASCII characters (RFC 2047)
	encodedSubject := encodeRFC2047(emailSubject)

	// Generate Date header (required by RFC 5322)
	dateHeader := time.Now().Format(time.RFC1123Z)

	// Escape HTML special characters in user inputs to prevent XSS and malformed HTML
	escapedUserName := html.EscapeString(userName)
	escapedSubject := html.EscapeString(subject)
	escapedFeedback := html.EscapeString(feedbackContent)

