// The email includes the username, feedback subject, and feedback content in HTML format.
func BuildFeedbackEmail(fromAddr string, toAddr string, userName string, subject string, feedbackContent string) (emailBody string, err error) {
	// Validate and parse email addresses
	from, err := mail.ParseAddress(fromAddr)
	if err != nil {
		return "", fmt.Errorf("invalid from address: %w", err)
	}

	to, err := mail.ParseAddress(toAddr)
	if err != nil {
		return "", fmt.Errorf("invalid to address: %w", err)
	}

	// Encode subject to support UTF-8 characters (RFC 2047)
	encodedSubject := mime.QEncoding.Encode("UTF-8", subject)

	// HTML template for the email body
	const htmlTemplate = `<!DOCTYPE html>
<html>
<head>
    <meta charset="UTF-8">
    <title>User Feedback</title>
    <style>
        body { font-family: Arial, sans-serif; line-height: 1.6; color: #333; max-width: 600px; margin: 0 auto; padding: 20px; }
        .header { background-color: #007bff; color: white; padding: 20px; text-align: center; border-radius: 5px 5px 0 0; }
        .content { background-color: #f4f4f4; padding: 20px; border: 1px solid #ddd; border-radius: 0 0 5px 5px; }
        .field { margin-bottom: 20px; }
        .label { font-weight: bold; color: #555; display: block; margin-bottom: 5px; font-size: 14px; text-transform: uppercase; }
        .value { background-color: white; padding: 12px; border-left: 4px solid #007bff; border-radius: 0 4px 4px 0; }
        .feedback-text { white-space: pre-wrap; word-wrap: break-word; font-family: inherit; }
    </style>
</head>
<body>
    <div class="header">
        <h2>New User Feedback Received</h2>
    </div>
    <div class="content">
        <div class="field">
            <span class="label">Username</span>
            <div class="value">{{.UserName}}</div>
        </div>
        <div class="field">
            <span class="label">Subject</span>
            <div class="value">{{.Subject}}</div>
        </div>
        <div class="field">
            <span class="label">Feedback Content</span>
            <div class="value feedback-text">{{.FeedbackContent}}</div>
        </div>
    </div>
</body>
</html>`

	type emailData struct {
		UserName        string
		Subject         string
		FeedbackContent string
	}

	data := emailData{
		UserName:        userName,
		Subject:         subject,
		FeedbackContent: feedbackContent,
	}

	// Parse and execute HTML template (auto-escapes HTML to prevent XSS)
	tmpl, err := template.New("feedbackEmail").Parse(htmlTemplate)
	if err != nil {
		return "", fmt.Errorf("failed to parse email template: %w", err)
	}

	var htmlBody bytes.Buffer
	if err := tmpl.Execute(&htmlBody, data); err != nil {
		return "", fmt.Errorf("failed to render email template: %w", err)
	}

	// Construct the complete email message with RFC 5322 headers
	var msg bytes.Buffer

	// Write headers
	msg.WriteString(fmt.Sprintf("From: %s\r\n", from.String()))
	msg.WriteString(fmt.Sprintf("To: %s\r\n", to.String()))
	msg.WriteString(fmt.Sprintf("Subject: %s\r\n", encodedSubject))
	msg.WriteString("MIME-Version: 1.0\r\n")
	msg.WriteString("Content-Type: text/html; charset=\"UTF-8\"\r\n")
	msg.WriteString("\r\n") // Empty line separates headers from body

	// Write HTML body
	msg.WriteString(htmlBody.String())

	return msg.String(), nil
}

func main() {
	// Example usage demonstrating the email generation
	// The returned string can be used with smtp.SendMail(addr, auth, from, []string{to}, []byte(emailBody))

	email, err := BuildFeedbackEmail(
		"customer@example.com",
		"support@company.com",
		"John Doe",
		"Application Crash on Startup",
		"The application crashes immediately after I click the login button.\n\nError details:\n- OS: Windows 11\n- Version: 2.5.1\n- Time: Every morning around 9 AM\n\nPlease fix this ASAP!",
	)
	if err != nil {
		fmt.Printf("Error building email: %v\n", err)
		return
	}

	fmt.Println("Generated Email Content:")
	fmt.Println("========================")
	fmt.Println(email)
}

