// BuildFeedbackEmail constructs an HTML-formatted email body for user feedback.
// The returned email body is a complete MIME message compatible with net/smtp.SendMail.
func BuildFeedbackEmail(fromAddr string, toAddr string, userName string, subject string, feedbackContent string) (emailBody string, err error) {
	// Validate email addresses
	from, err := mail.ParseAddress(fromAddr)
	if err != nil {
		return "", fmt.Errorf("invalid from address: %w", err)
	}

	to, err := mail.ParseAddress(toAddr)
	if err != nil {
		return "", fmt.Errorf("invalid to address: %w", err)
	}

	// Sanitize subject to prevent header injection
	safeSubjectHeader := strings.ReplaceAll(subject, "\r", " ")
	safeSubjectHeader = strings.ReplaceAll(safeSubjectHeader, "\n", " ")
	fullSubject := "User Feedback: " + safeSubjectHeader

	// Build email headers
	var buf bytes.Buffer

	buf.WriteString("MIME-Version: 1.0\r\n")
	buf.WriteString("Content-Type: text/html; charset=\"UTF-8\"\r\n")
	buf.WriteString("Content-Transfer-Encoding: 8bit\r\n")
	buf.WriteString(fmt.Sprintf("Date: %s\r\n", time.Now().Format(time.RFC1123)))
	buf.WriteString(fmt.Sprintf("From: %s\r\n", from.String()))
	buf.WriteString(fmt.Sprintf("To: %s\r\n", to.String()))

	// Encode subject if non-ASCII (RFC 2047)
	if hasNonASCII(fullSubject) {
		encodedSubject := base64.StdEncoding.EncodeToString([]byte(fullSubject))
		buf.WriteString(fmt.Sprintf("Subject: =?UTF-8?B?%s?=\r\n", encodedSubject))
	} else {
		buf.WriteString(fmt.Sprintf("Subject: %s\r\n", fullSubject))
	}

	buf.WriteString("\r\n") // Empty line separating headers from body

	// Build HTML body
	htmlBody := buildHTMLBody(userName, subject, feedbackContent)

	// Ensure CRLF line endings for SMTP compliance
	htmlBody = strings.ReplaceAll(htmlBody, "\r\n", "\n")
	htmlBody = strings.ReplaceAll(htmlBody, "\n", "\r\n")

	buf.WriteString(htmlBody)

	return buf.String(), nil
}

func hasNonASCII(s string) bool {
	for _, r := range s {
		if r > 127 {
			return true
		}
	}
	return false
}

func wrapLines(s string, limit int) string {
	if limit <= 0 {
		return s + "\r\n"
	}
	var result strings.Builder
	for i := 0; i < len(s); i += limit {
		end := i + limit
		if end > len(s) {
