// BuildFeedbackEmail constructs an HTML-formatted email body for user feedback.
// It creates a properly formatted RFC 822 message with MIME headers and HTML content
// containing the user's submitted information, ready to be sent via SMTP.
func BuildFeedbackEmail(fromAddr string, toAddr string, userName string, subject string, feedbackContent string) (emailBody string, err error) {
	// Parse and validate email addresses using net/mail
	from, err := mail.ParseAddress(fromAddr)
	if err != nil {
		return "", fmt.Errorf("invalid from address: %w", err)
	}

	to, err := mail.ParseAddress(toAddr)
	if err != nil {
		return "", fmt.Errorf("invalid to address: %w", err)
	}

	// Construct email headers with proper CRLF line endings
	var headers strings.Builder
	headers.WriteString(fmt.Sprintf("From: %s\r\n", from.String()))
	headers.WriteString(fmt.Sprintf("To: %s\r\n", to.String()))
	headers.WriteString(fmt.Sprintf("Subject: %s\r\n", encodeRFC2047(subject)))
	headers.WriteString("MIME-Version: 1.0\r\n")
	headers.WriteString("Content-Type: text/html; charset=\"UTF-8\"\r\n")
	headers.WriteString("\r\n") // Empty line separating headers from body

	// Generate HTML body with user feedback information
	htmlBody := buildHTMLBody(userName, subject, feedbackContent)

	return headers.String() + htmlBody, nil
}

// encodeRFC2047 encodes a string using RFC 2047 Base64 encoding for email headers.
// This ensures UTF-8 characters in the subject are properly transmitted.
func encodeRFC2047(s string) string {
	if s == "" {
		return ""
	}
	// Format: =?charset?encoding?encoded-text?=
	return fmt.Sprintf("=?UTF-8?B?%s?=", base64.StdEncoding.EncodeToString([]byte(s)))
}

